-- MoneyModule.lua\n-- Módulo para gestionar el dinero del jugador\n-- Se guarda en ReplicatedStorage\n\nlocal MoneyModule = {}\n\n-- Variables locales\nlocal player_money = {}\n\n-- Obtiene el dinero de un jugador\nfunction MoneyModule:GetMoney(player)\n\tif not player_money[player.UserId] then\n\t\tplayer_money[player.UserId] = {\n\t\t\tcash = 100,\n\t\t\tbank_balance = 0,\n\t\t\ttotal_debt = 0\n\t\t}\n\tend\n\treturn player_money[player.UserId].cash\nend\n\n-- Obtiene el total de dinero (efectivo + banco)\nfunction MoneyModule:GetTotalMoney(player)\n\tlocal data = player_money[player.UserId]\n\tif not data then\n\t\treturn 0\n\tend\n\treturn data.cash + data.bank_balance\nend\n\n-- Añade dinero en efectivo\nfunction MoneyModule:AddMoney(player, amount)\n\tif amount <= 0 then\n\t\tprint(\"Error: No se puede añadir cantidad negativa\")\n\t\treturn false\n\tend\n\t\n\tif not player_money[player.UserId] then\n\t\tplayer_money[player.UserId] = {\n\t\t\tcash = 0,\n\t\t\tbank_balance = 0,\n\t\t\ttotal_debt = 0\n\t\t}\n\tend\n\t\n\tplayer_money[player.UserId].cash = player_money[player.UserId].cash + amount\n\tprint(\"[MoneyModule] +$\" .. amount .. \" al jugador \" .. player.Name)\n\treturn true\nend\n\n-- Resta dinero en efectivo\nfunction MoneyModule:RemoveMoney(player, amount)\n\tif amount <= 0 then\n\t\tprint(\"Error: No se puede restar cantidad negativa\")\n\t\treturn false\n\tend\n\t\n\tif not player_money[player.UserId] then\n\t\treturn false\n\tend\n\t\n\tif player_money[player.UserId].cash < amount then\n\t\tprint(\"Error: Dinero insuficiente\")\n\t\treturn false\n\tend\n\t\n\tplayer_money[player.UserId].cash = player_money[player.UserId].cash - amount\n\tprint(\"[MoneyModule] -$\" .. amount .. \" al jugador \" .. player.Name)\n\treturn true\nend\n\n-- Deposita dinero en el banco\nfunction MoneyModule:DepositToBank(player, amount)\n\tif not self:RemoveMoney(player, amount) then\n\t\treturn false\n\tend\n\t\n\tplayer_money[player.UserId].bank_balance = player_money[player.UserId].bank_balance + amount\n\tprint(\"[MoneyModule] Depositado $\" .. amount .. \" en el banco de \" .. player.Name)\n\treturn true\nend\n\n-- Retira dinero del banco\nfunction MoneyModule:WithdrawFromBank(player, amount)\n\tif not player_money[player.UserId] then\n\t\treturn false\n\tend\n\t\n\tif player_money[player.UserId].bank_balance < amount then\n\t\tprint(\"Error: Balance insuficiente en el banco\")\n\t\treturn false\n\tend\n\t\n\tplayer_money[player.UserId].bank_balance = player_money[player.UserId].bank_balance - amount\n\tplayer_money[player.UserId].cash = player_money[player.UserId].cash + amount\n\tprint(\"[MoneyModule] Retirado $\" .. amount .. \" del banco de \" .. player.Name)\n\treturn true\nend\n\n-- Obtiene el balance del banco\nfunction MoneyModule:GetBankBalance(player)\n\tif not player_money[player.UserId] then\n\t\treturn 0\n\tend\n\treturn player_money[player.UserId].bank_balance\nend\n\n-- Obtiene la deuda actual\nfunction MoneyModule:GetDebt(player)\n\tif not player_money[player.UserId] then\n\t\treturn 0\n\tend\n\treturn player_money[player.UserId].total_debt\nend\n\n-- Solicita un préstamo\nfunction MoneyModule:TakeLoan(player, amount)\n\tif amount <= 0 then\n\t\tprint(\"Error: Cantidad inválida\")\n\t\treturn false\n\tend\n\t\n\tif not player_money[player.UserId] then\n\t\tplayer_money[player.UserId] = {\n\t\t\tcash = 0,\n\t\t\tbank_balance = 0,\n\t\t\ttotal_debt = 0\n\t\t}\n\tend\n\t\n\tself:AddMoney(player, amount)\n\tplayer_money[player.UserId].total_debt = player_money[player.UserId].total_debt + amount\n\tprint(\"[MoneyModule] Préstamo de $\" .. amount .. \" a \" .. player.Name)\n\treturn true\nend\n\n-- Paga una deuda\nfunction MoneyModule:PayDebt(player, amount)\n\tif not self:RemoveMoney(player, amount) then\n\t\treturn false\n\tend\n\t\n\tlocal debt = player_money[player.UserId].total_debt\n\tplayer_money[player.UserId].total_debt = math.max(0, debt - amount)\n\tprint(\"[MoneyModule] Deuda pagada: $\" .. amount .. \" por \" .. player.Name)\n\treturn true\nend\n\n-- Obtiene un resumen financiero\nfunction MoneyModule:GetFinancialSummary(player)\n\tif not player_money[player.UserId] then\n\t\treturn nil\n\tend\n\t\n\tlocal data = player_money[player.UserId]\n\treturn {\n\t\tcash = data.cash,\n\t\tbank_balance = data.bank_balance,\n\t\ttotal_money = data.cash + data.bank_balance,\n\t\tdebt = data.total_debt\n\t}\nend\n\nreturn MoneyModule\n", "path": "scripts/MoneyModule.lua